import boto3
import json
import base64

def get_message(queue_url):
    sqs = boto3.client('sqs', region_name='us-west-2')
    response = sqs.receive_message(
        QueueUrl=queue_url,
        WaitTimeSeconds=20
    )

    if 'Messages' in response:
        message = response['Messages'][0]
        receipt_handle = message['ReceiptHandle']
